import React, { useState } from 'react'
import UI from './portfolioComponents/ui/UI'
import { photos } from "../components/PortfolioImages/PortfolioImages";
import { designPhotos } from "../components/PortfolioImages/PortfolioImagesDesigns";

const Portfolio = () => {

    const data = [
        {
            id: '1',
            tabTitle: "UI + Front-End",
            tabContent: <UI photos={photos}/>
        },
        {
            id: '2',
            tabTitle: "Attractive Designs",
            tabContent: <UI photos={designPhotos}/>
        }
    ]

    const [visibleTab, setVisibleTab] = useState(data[0].id)

    const listTitles = data.map((item) =>
        <li key={item.id} onClick={() => setVisibleTab(item.id)} className={visibleTab === item.id ? "tab-title tab-title--active" : "tab-title"}>{item.tabTitle}</li>
    )

    const listContent = data.map((item) =>
        <div key={item.id} style={visibleTab === item.id ? {} : { display: 'none' }}>{item.tabContent}</div>
    )


    return (
        <div className="portfolio-gallery">
            <div className="portfolio-title">
                <h2>Portfolio</h2>
            </div>

            <div className="tabs">
                <ul className="tabs-titles">
                    {listTitles}
                </ul>
                <div className="tab-content">
                    {listContent}
                </div>
            </div>

        </div>
    )
}

export default Portfolio
