import React from 'react'
import AboutImage from '../assets/images/about-image.jpg'
import BackgroundOne from './backgrounds/BackgroundOne'
import { HiDownload } from 'react-icons/hi';

const AboutMe = () => {

    const downloadCV = () => {
        window.open("https://drive.google.com/file/d/1C0xQeZABzgT3kvHU4PLh3WwH4SZbSIq6/view?usp=sharing");
    }

    return (
        <div className="about-me-section">
            <BackgroundOne style="about-me-bg" />
            <BackgroundOne style="about-me-bg-two" />
            <div className="about-me-main container">
                <div className="my-image">
                    <img src={AboutImage} alt="" />
                </div>
                <div className="about-me">
                    <div className="my-info">
                        <div>
                            <div><span>Name : </span> Eshan Rajapakshe</div>
                            <div><span>Email : </span> <a href="mailto:">eshanrajapakse@gmail.com</a></div>
                        </div>
                        <div>
                            <div><span>Mobile : </span> <a href="tel:+">+94 777712007</a></div>
                            <div><span>LinkedIn : </span> <a href="https://www.linkedin.com/in/eshan-rajapakshe/" target="_blank" rel="noopener noreferrer">www.linkedin.com/in/eshan-rajapakshe</a></div>
                        </div>
                    </div>
                    <h3>I'm A User Interface and Front-end Developer</h3>
                    <p>I am a resourceful and talented user experience/user interface and front-end developer. A self-learner, hard worker who is looking at a career path with new
                        learning outcomes to persuade personal and corporate goals. I believe innovative ideas and creativity has always directed me towards the way of success.</p>
                    <div className="about-sub-section">
                        <div>
                            <button type="button" onClick={downloadCV} className="btn read-more-btn">Download CV <HiDownload size="1.1em" className="cv-download-icon" /></button>
                        </div>
                        <div className="experience-main">
                            <h6>Experience</h6>
                            <div>
                                <h1>3</h1>
                                <span>+ YEARS</span>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>

    )
}

export default AboutMe
